arguments.command:
$url = "$($env:SUPABASE_URL)/rest/v1/agent_metrics?select=agent_id,metric_type,metric_value,metadata,recorded_at&order=recorded_at.desc&limit=2000";
$data = curl.exe -k -sS -H "apikey: $env:SUPABASE_SERVICE_ROLE_KEY" -H "Authorization: Bearer $env:SUPABASE_SERVICE_ROLE_KEY" "$url" | ConvertFrom-Json;
if ($null -eq $data) { 'null' } else { $data.Count; $data | Select-Object -First 3 | ConvertTo-Json -Depth 6 }

$url = "$($env:SUPABASE_URL)/rest/v1/agent_events";
$payload = @{
  event_name = "agent/escalate"
  source_agent = "shared_master_orchestrator"
  target_agent = "d1_cto"
  target_division = "division_1_core_operations"
  payload = @{
    severity = "critical"
    summary = "agent_metrics telemetry gap and stale heartbeats"
    details = @{
      stale_heartbeat_agents = 65
      stale_threshold_minutes = 30
      agent_metrics_rows = 0
      checks_blocked = @("error_rate", "response_time", "memory_utilization")
      observed_at_utc = "2026-03-13T15:07:00Z"
    }
  }
  priority = "high"
} | ConvertTo-Json -Depth 8 -Compress;
curl.exe -k -sS -X POST -H "Content-Type: application/json" -H "Prefer: return=representation" -H "apikey: $env:SUPABASE_SERVICE_ROLE_KEY" -H "Authorization: Bearer $env:SUPABASE_SERVICE_ROLE_KEY" -d $payload "$url"

